193	                    procR2.add(r2);
194	                    return r2;
195	                }));
196	
197	
198	        // 4. results handler (E) after matching engine (ME) + [journaling (J)]
199	        final EventHandlerGroup<OrderCommand> mainHandlerGroup = enableJournaling
200	                ? disruptor.after(arraysAddHandler(matchingEngineHandlers, jh))
