48	        this.sequenceBarrier = sequenceBarrier;
49	        this.waitSpinningHelper = new WaitSpinningHelper(ringBuffer, sequenceBarrier, 0, CoreWaitStrategy.SECOND_STEP_NO_WAIT);
50	        this.eventHandler = eventHandler;
51	        this.exceptionHandler = exceptionHandler;
52	        this.name = name;
53	    }
