72	     * It is ok to have another thread rerun this method after a halt().
73	     *
74	     * @throws IllegalStateException if this object instance is already running in a thread
75	     */
76	    @Override
77	    public void run() {
78	        if (running.compareAndSet(IDLE, RUNNING)) {
79	            sequenceBarrier.clearAlert();
80	        } else if (running.get() == RUNNING) {

 80	        } else if (running.get() == RUNNING) {
 81	            throw new IllegalStateException("Thread is already running (S)");
 82	        }
 83	
 84	        nextSequence = sequence.get() + 1L;
 85	    }
