```java
public long tryWaitFor(final long seq) throws AlertException, InterruptedException {
    sequenceBarrier.checkAlert();
    long spin = spinLimit;
    long availableSequence;
    while ((availableSequence = sequenceBarrier.getCursor()) < seq && spin > 0) {
